
.m-profile {
  padding: var(--mobile-padding);
  display: flex;
  flex-direction: column;
  gap: 8px;
}

// ═══ 头部卡片 ═══
.profile-header-card {
  background: linear-gradient(135deg, rgba(196, 30, 58, 0.08) 0%, rgba(74, 144, 217, 0.05) 100%);
  border: 1px solid var(--color-border);
  border-radius: var(--mobile-radius);
  padding: var(--mobile-padding);
}

.profile-top {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  margin-bottom: 8px;
}

.name-area {
  display: flex;
  align-items: center;
  gap: 8px;

  h2 {
    font-size: 20px;
    font-weight: 700;
    color: var(--color-text-primary);
    margin: 0;
  }
}

.level-badge {
  padding: 2px 8px;
  font-size: 11px;
  font-weight: 600;
  background: rgba(216, 166, 87, 0.15);
  border: 1px solid rgba(216, 166, 87, 0.3);
  border-radius: var(--radius-full);
  color: var(--color-gold);
}

.position-area {
  text-align: right;
  .position-title {
    display: block;
    font-size: 13px;
    font-weight: 600;
    color: var(--color-text-primary);
  }
  .position-unit {
    font-size: 11px;
    color: var(--color-text-muted);
  }
}

.info-chips {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.chip {
  padding: 2px 8px;
  font-size: 11px;
  background: var(--color-bg-elevated);
  border-radius: var(--radius-full);
  color: var(--color-text-secondary);
}

// ═══ 晋升条 ═══
.promotion-bar {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 10px var(--mobile-padding);
  background: rgba(74, 193, 142, 0.08);
  border: 1px solid rgba(74, 193, 142, 0.2);
  border-radius: var(--mobile-radius);
  font-size: 13px;
  font-weight: 600;
  color: var(--color-success);

  i { font-size: 16px; }

  &.frozen {
    background: rgba(255, 107, 107, 0.08);
    border-color: rgba(255, 107, 107, 0.2);
    color: var(--color-danger);
  }

  .next-target {
    font-weight: 400;
    font-size: 12px;
    color: var(--color-text-muted);
  }
}

// ═══ 雷达图容器 ═══
.radar-body {
  display: flex;
  justify-content: center;
  padding: 8px;
}

// ═══ 键值列表 ═══
.kv-list {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.kv-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 6px 10px;
  background: var(--color-bg-elevated);
  border-radius: var(--radius-sm);

  .kv-key {
    font-size: 12px;
    color: var(--color-text-muted);
  }

  .kv-val {
    font-size: 12px;
    color: var(--color-text-secondary);
    font-weight: 500;
    text-align: right;
    max-width: 60%;
  }
}

// ═══ 记录 ═══
.record-block {
  margin-bottom: 8px;

  &:last-child { margin-bottom: 0; }
}

.record-label {
  display: flex;
  align-items: center;
  gap: 4px;
  font-size: 11px;
  font-weight: 600;
  color: var(--color-text-muted);
  margin-bottom: 6px;

  i { font-size: 10px; }
}

.rec-name {
  font-size: 13px;
  font-weight: 600;
  color: var(--color-text-primary);
}

.rec-meta {
  font-size: 11px;
  color: var(--color-text-muted);
  margin-top: 2px;
}

// ═══ 项目 ═══
.proj-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.proj-name {
  font-size: 13px;
  font-weight: 600;
  color: var(--color-text-primary);
}

.proj-status {
  font-size: 10px;
  padding: 2px 6px;
  border-radius: var(--radius-sm);
  background: var(--color-bg-card);
  color: var(--color-text-muted);

  &.good { color: var(--color-success); background: rgba(74, 193, 142, 0.12); }
  &.bad { color: var(--color-danger); background: rgba(255, 107, 107, 0.12); }
}

.proj-meta {
  display: flex;
  gap: 12px;
  margin-top: 4px;
  font-size: 11px;
  color: var(--color-text-muted);

  i { margin-right: 4px; font-size: 10px; }
}

// ═══ 时间线 ═══
.timeline-list {
  display: flex;
  flex-direction: column;
  gap: 0;
  padding-left: 8px;
}

.timeline-item {
  display: flex;
  gap: 12px;
  position: relative;
  padding-bottom: 12px;

  &:last-child { padding-bottom: 0; }

  &::before {
    content: '';
    position: absolute;
    left: 4px;
    top: 12px;
    bottom: 0;
    width: 2px;
    background: var(--color-border);
  }

  &:last-child::before { display: none; }
}

.tl-dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  background: var(--color-gold);
  border: 2px solid var(--color-bg-card);
  flex-shrink: 0;
  margin-top: 4px;
  z-index: 1;
}

.tl-content {
  flex: 1;
}

.tl-header {
  display: flex;
  align-items: center;
  gap: 6px;
}

.tl-title {
  font-size: 13px;
  font-weight: 600;
  color: var(--color-text-primary);
}

.tl-level {
  font-size: 10px;
  padding: 1px 6px;
  background: rgba(216, 166, 87, 0.12);
  border-radius: var(--radius-sm);
  color: var(--color-gold);
}

.tl-period {
  font-size: 11px;
  color: var(--color-text-muted);
  margin-top: 2px;
}

.tl-unit {
  font-size: 11px;
  color: var(--color-text-muted);
  margin-top: 2px;
  i { font-size: 10px; margin-right: 4px; }
}

.tl-desc {
  font-size: 12px;
  color: var(--color-text-secondary);
  margin: 4px 0 0;
  line-height: 1.5;
}

.empty-hint {
  text-align: center;
  color: var(--color-text-muted);
  font-size: 13px;
  padding: 16px;
}
