
.m-variables {
  padding: var(--mobile-padding);
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.var-toolbar {
  display: flex; gap: 6px;
}

.search-input {
  flex: 1;
  display: flex; align-items: center; gap: 8px;
  padding: 8px 12px;
  background: var(--color-bg-card); border: 1px solid var(--color-border);
  border-radius: var(--mobile-radius);

  i { color: var(--color-text-muted); font-size: 14px; }
  input { flex: 1; background: transparent; color: var(--color-text-primary); border: none; outline: none; font-size: 14px; }
}

.toolbar-actions { display: flex; gap: 4px; }

.toolbar-btn {
  width: var(--touch-min-size); height: var(--touch-min-size);
  display: flex; align-items: center; justify-content: center;
  background: var(--color-bg-card); border: 1px solid var(--color-border);
  border-radius: var(--radius-md); color: var(--color-text-muted);

  &.save { color: var(--color-gold); border-color: var(--color-gold); &:disabled { opacity: 0.3; } }
}

.filter-row {
  display: flex; align-items: center; justify-content: space-between;
}

.filter-toggle {
  display: flex; align-items: center; gap: 6px; font-size: 12px; color: var(--color-text-muted);
  input { accent-color: var(--color-gold); }
}

.startup-confirm-btn {
  padding: 8px 16px; background: var(--color-romance); color: white;
  border-radius: var(--radius-md); font-size: 13px; font-weight: 600;
  min-height: var(--touch-min-size);
}

.sections { display: flex; flex-direction: column; gap: 4px; }

.dirty-dot {
  width: 8px; height: 8px; background: var(--color-gold); border-radius: 50%;
}

.json-editor {
  textarea {
    width: 100%; padding: 10px; background: var(--color-bg-elevated);
    border: 1px solid var(--color-border); border-radius: var(--radius-md);
    color: var(--color-text-primary); font-size: 12px; font-family: 'Consolas', monospace;
    line-height: 1.5; resize: vertical; min-height: 120px;
    &:focus { border-color: var(--color-gold); outline: none; }
  }
}

.editor-actions { display: flex; justify-content: flex-end; margin-top: 6px; }

.save-section-btn {
  padding: 8px 16px; background: var(--color-gold); color: var(--color-bg-dark);
  border-radius: var(--radius-md); font-size: 12px; font-weight: 600;
  min-height: var(--touch-min-size);
}

// 导入弹窗
.import-modal {
  position: fixed; inset: 0; background: rgba(0, 0, 0, 0.7); z-index: 100;
  display: flex; align-items: flex-end;
}

.import-dialog {
  width: 100%; background: var(--color-bg-card);
  border-radius: var(--mobile-radius) var(--mobile-radius) 0 0;
  max-height: 80vh; display: flex; flex-direction: column;
}

.import-header {
  display: flex; align-items: center; justify-content: space-between;
  padding: var(--mobile-padding); border-bottom: 1px solid var(--color-border);
  h3 { font-size: 15px; font-weight: 600; color: var(--color-text-primary); margin: 0;
    i { color: var(--color-gold); margin-right: 6px; } }
  button { width: 32px; height: 32px; display: flex; align-items: center; justify-content: center;
    background: var(--color-bg-elevated); border-radius: var(--radius-md); color: var(--color-text-muted); }
}

.import-body {
  padding: var(--mobile-padding); flex: 1; overflow-y: auto;
  textarea {
    width: 100%; padding: 10px; background: var(--color-bg-elevated);
    border: 1px solid var(--color-border); border-radius: var(--radius-md);
    color: var(--color-text-primary); font-size: 12px; font-family: 'Consolas', monospace;
    line-height: 1.5; resize: vertical;
    &:focus { border-color: var(--color-gold); outline: none; }
  }
}

.import-footer {
  display: flex; gap: 8px; padding: var(--mobile-padding);
  padding-bottom: calc(var(--mobile-padding) + env(safe-area-inset-bottom, 0));
  border-top: 1px solid var(--color-border);

  button { flex: 1; padding: 12px; border-radius: var(--radius-md); font-size: 14px; font-weight: 600; min-height: var(--touch-min-size); }
  .cancel-btn { background: var(--color-bg-elevated); color: var(--color-text-secondary); border: 1px solid var(--color-border); }
  .confirm-btn { background: var(--color-gold); color: var(--color-bg-dark); }
}
