
.m-settings {
  padding: var(--mobile-padding);
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.page-title {
  font-size: 18px; font-weight: 700; color: var(--color-text-primary); margin: 0;
  i { color: var(--color-gold); margin-right: 6px; }
}

.setting-section {
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--mobile-radius);
  padding: var(--mobile-padding);
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.section-title {
  font-size: 14px; font-weight: 600; color: var(--color-text-primary);
  i { color: var(--color-gold); margin-right: 6px; font-size: 12px; }
}

.toggle-row {
  display: flex; align-items: center; justify-content: space-between;
}

.toggle-info { display: flex; flex-direction: column; gap: 2px; }
.toggle-label { font-size: 13px; font-weight: 500; color: var(--color-text-primary); }
.toggle-desc { font-size: 11px; color: var(--color-text-muted); }

.mobile-toggle {
  position: relative; width: 44px; height: 24px;
  input { opacity: 0; width: 0; height: 0; }
  .slider {
    position: absolute; inset: 0; background: var(--color-bg-elevated);
    border: 1px solid var(--color-border); border-radius: 12px; transition: 0.2s;
    &::before {
      content: ''; position: absolute; width: 16px; height: 16px;
      left: 3px; bottom: 3px; background: var(--color-text-muted);
      border-radius: 50%; transition: 0.2s;
    }
  }
  input:checked + .slider { background: var(--color-gold); border-color: var(--color-gold);
    &::before { transform: translateX(20px); background: var(--color-bg-dark); }
  }
}

.status-row {
  display: flex; align-items: center; gap: 8px; font-size: 12px; color: var(--color-text-muted);
  padding: 6px 10px; background: var(--color-bg-elevated); border-radius: var(--radius-sm);
  i { font-size: 8px; }
  .status-ready { color: var(--color-success); }
  .status-parsing { color: var(--color-warning); animation: pulse 1s infinite; }
  .status-pending { color: var(--color-info); animation: pulse 1.5s infinite; }
  .status-warning { color: var(--color-danger); }
}

@keyframes pulse { 0%, 100% { opacity: 1; } 50% { opacity: 0.5; } }

.input-row {
  display: flex; flex-direction: column; gap: 4px;
  label { font-size: 12px; color: var(--color-text-muted); }
  input, select {
    padding: 10px; background: var(--color-bg-elevated); border: 1px solid var(--color-border);
    border-radius: var(--radius-md); color: var(--color-text-primary); font-size: 14px;
    min-height: var(--touch-min-size);
    &:focus { border-color: var(--color-gold); outline: none; }
  }
  &.compact { input { padding: 8px; font-size: 13px; } }
}

.input-with-btn {
  display: flex; gap: 6px;
  input, select { flex: 1; }
  button {
    width: var(--touch-min-size); height: var(--touch-min-size); display: flex; align-items: center; justify-content: center;
    background: var(--color-bg-elevated); border: 1px solid var(--color-border); border-radius: var(--radius-md);
    color: var(--color-text-muted); font-size: 14px;
  }
}

.slider-row {
  display: flex; flex-direction: column; gap: 4px;
  label { font-size: 12px; color: var(--color-text-muted); small { color: var(--color-gold); margin-left: 4px; } }
  input[type="range"] { width: 100%; accent-color: var(--color-gold); }
}

.adv-params { display: flex; flex-direction: column; gap: 8px; }

.preset-grid {
  display: grid; grid-template-columns: repeat(3, 1fr); gap: 6px; margin-top: 6px;
}

.preset-btn {
  padding: 8px; background: var(--color-bg-elevated); border: 1px solid var(--color-border);
  border-radius: var(--radius-md); color: var(--color-text-muted); font-size: 12px;
  min-height: var(--touch-min-size);
  &.active { border-color: var(--color-gold); color: var(--color-gold); background: rgba(216, 166, 87, 0.08); }
}

.ratio-display {
  font-size: 11px; color: var(--color-text-muted); text-align: right;
}

.warning-bar {
  display: flex; align-items: center; gap: 8px; padding: 10px;
  background: rgba(255, 107, 107, 0.1); border: 1px solid rgba(255, 107, 107, 0.3);
  border-radius: var(--mobile-radius); color: var(--color-danger); font-size: 13px;
}
