
.mvu-confirm-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.6);
  backdrop-filter: blur(4px);
  display: flex;
  align-items: flex-end;
  justify-content: center;
  padding: var(--spacing-lg);
  z-index: var(--z-modal);
}

.mvu-confirm-dialog {
  width: 100%;
  max-width: 800px;
  max-height: 85vh;
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  display: flex;
  flex-direction: column;
  box-shadow: var(--shadow-lg);
}

// ═══ Header ═══
.dialog-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--spacing-md) var(--spacing-lg);
  background: var(--color-bg-elevated);
  border-bottom: 1px solid var(--color-border);
  border-radius: var(--radius-lg) var(--radius-lg) 0 0;
}

.header-title {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  font-size: 16px;
  font-weight: 600;
  color: var(--color-text-primary);

  i {
    color: var(--color-gold);
  }

  .cmd-count {
    font-size: 12px;
    font-weight: 400;
    color: var(--color-text-muted);
    background: var(--color-bg-dark);
    padding: 2px 8px;
    border-radius: var(--radius-sm);
  }

  .validation-badge {
    display: flex;
    align-items: center;
    gap: 4px;
    font-size: 11px;
    font-weight: 500;
    padding: 3px 8px;
    border-radius: var(--radius-sm);

    &.error {
      background: rgba(255, 107, 107, 0.15);
      color: var(--color-danger);
      animation: pulse-error 2s infinite;
    }

    &.success {
      background: rgba(74, 193, 142, 0.15);
      color: var(--color-success);
    }
  }

  @keyframes pulse-error {
    0%,
    100% {
      opacity: 1;
    }
    50% {
      opacity: 0.7;
    }
  }
}

.header-actions {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
}

.view-toggle {
  display: flex;
  background: var(--color-bg-dark);
  border-radius: var(--radius-sm);
  padding: 2px;
  margin-right: var(--spacing-sm);

  .toggle-btn {
    padding: 6px 10px;
    background: transparent;
    border: none;
    border-radius: var(--radius-xs);
    color: var(--color-text-muted);
    transition: all var(--transition-fast);

    &:hover {
      color: var(--color-text-primary);
    }

    &.active {
      background: var(--color-gold);
      color: var(--color-bg-dark);
    }
  }
}

.btn-action {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 32px;
  height: 32px;
  background: transparent;
  border: 1px solid var(--color-border);
  border-radius: var(--radius-sm);
  color: var(--color-text-muted);
  transition: all var(--transition-fast);

  &:hover {
    background: var(--color-bg-dark);
    color: var(--color-text-primary);
  }

  &.btn-close:hover {
    color: var(--color-danger);
    border-color: var(--color-danger);
  }
}

// ═══ Body ═══
.dialog-body {
  flex: 1;
  overflow-y: auto;
  padding: var(--spacing-lg);
}

.section-label {
  display: flex;
  align-items: center;
  gap: var(--spacing-xs);
  font-size: 13px;
  font-weight: 600;
  color: var(--color-text-secondary);
  margin-bottom: var(--spacing-sm);

  i {
    color: var(--color-gold);
  }
}

.mt-lg {
  margin-top: var(--spacing-lg);
}

.label-hint {
  margin-left: auto;
  font-size: 11px;
  font-weight: 400;
  color: var(--color-text-muted);
  background: var(--color-bg-dark);
  padding: 2px 6px;
  border-radius: var(--radius-sm);
}

// ═══ Code View ═══
.code-editor {
  width: 100%;
  min-height: 180px;
  padding: var(--spacing-md);
  background: var(--color-bg-dark);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  font-family: var(--font-mono);
  font-size: 13px;
  line-height: 1.6;
  color: var(--color-text-primary);
  resize: vertical;
  transition:
    border-color var(--transition-fast),
    box-shadow var(--transition-fast);

  &:focus {
    border-color: var(--color-gold);
    outline: none;
  }

  // 定位错误时的闪烁效果
  &.editor-flash {
    animation: editor-flash-anim 0.5s ease-in-out 2;
    border-color: var(--color-danger);
    box-shadow: 0 0 0 3px rgba(255, 107, 107, 0.3);
  }
}

@keyframes editor-flash-anim {
  0%,
  100% {
    box-shadow: 0 0 0 3px rgba(255, 107, 107, 0.3);
  }
  50% {
    box-shadow: 0 0 0 6px rgba(255, 107, 107, 0.5);
  }
}

.preview-content {
  padding: var(--spacing-md);
  background: var(--color-bg-dark);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
}

.parsed-preview {
  max-height: 300px;
  overflow-y: auto;
}

.command-item {
  display: flex;
  flex-wrap: wrap;
  align-items: flex-start;
  gap: var(--spacing-sm);
  padding: var(--spacing-sm) 0;
  font-family: var(--font-mono);
  font-size: 12px;
  line-height: 1.5;

  & + & {
    border-top: 1px solid var(--color-border);
  }
}

.cmd-type {
  padding: 2px 6px;
  border-radius: var(--radius-sm);
  font-weight: 600;
  text-transform: uppercase;
  font-size: 10px;
  flex-shrink: 0;

  &.type-set,
  &.type-replace {
    background: rgba(74, 193, 142, 0.2);
    color: var(--color-success);
  }

  &.type-add {
    background: rgba(122, 162, 247, 0.2);
    color: var(--color-info);
  }

  &.type-insert,
  &.type-assign {
    background: rgba(216, 166, 87, 0.2);
    color: var(--color-gold);
  }

  &.type-delete,
  &.type-remove,
  &.type-unset {
    background: rgba(255, 107, 107, 0.2);
    color: var(--color-danger);
  }
}

.cmd-path {
  color: var(--color-text-primary);
  word-break: break-all;
}

.cmd-arrow {
  color: var(--color-text-muted);
}

.cmd-value {
  color: var(--color-success);
  word-break: break-all;
}

.cmd-reason {
  width: 100%;
  color: var(--color-text-muted);
  font-style: italic;
  padding-left: var(--spacing-sm);
}

.no-commands {
  color: var(--color-text-muted);
  text-align: center;
  padding: var(--spacing-lg);

  i {
    margin-right: var(--spacing-xs);
  }
}

// 验证错误样式
.command-item {
  &.has-error {
    background: rgba(255, 107, 107, 0.08);
    border-left: 3px solid var(--color-danger);
    padding-left: var(--spacing-sm);
    margin-left: calc(-1 * var(--spacing-sm));
  }

  // 当前定位的错误 - 更明显的高亮
  &.current-error {
    background: rgba(255, 107, 107, 0.2) !important;
    border-left: 4px solid var(--color-danger) !important;
    box-shadow: 0 0 0 2px rgba(255, 107, 107, 0.3);
    position: relative;

    &::before {
      content: '→';
      position: absolute;
      left: -20px;
      top: 50%;
      transform: translateY(-50%);
      color: var(--color-danger);
      font-weight: bold;
      font-size: 16px;
    }
  }

  // 闪烁效果
  &.error-flash {
    animation: error-flash-anim 0.5s ease-in-out 2;
  }

  .cmd-main {
    display: flex;
    flex-wrap: wrap;
    align-items: flex-start;
    gap: var(--spacing-sm);
  }

  .value-error {
    color: var(--color-danger) !important;
    text-decoration: line-through;
    opacity: 0.8;
  }

  .cmd-errors {
    display: flex;
    flex-direction: column;
    gap: var(--spacing-xs);
    margin-top: var(--spacing-sm);
  }

  .cmd-error {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    gap: var(--spacing-sm);
    padding: var(--spacing-xs) var(--spacing-sm);
    background: rgba(255, 107, 107, 0.1);
    border-radius: var(--radius-sm);
    font-size: 11px;

    i {
      color: var(--color-danger);
      flex-shrink: 0;
    }

    .error-path {
      color: var(--color-danger);
      font-weight: 600;
      font-family: var(--font-mono);
      background: rgba(255, 107, 107, 0.15);
      padding: 1px 4px;
      border-radius: 2px;
    }

    .error-message {
      color: var(--color-danger);
      font-weight: 500;
    }

    .expected-type {
      color: var(--color-text-muted);
      font-style: italic;
      margin-left: auto;
    }
  }
}

// ═══ Interactive View ═══
.no-commands-card {
  text-align: center;
  padding: var(--spacing-xl);
  background: var(--color-bg-dark);
  border-radius: var(--radius-md);
  border: 1px dashed var(--color-border);

  i {
    font-size: 32px;
    color: var(--color-text-muted);
    margin-bottom: var(--spacing-md);
  }

  p {
    color: var(--color-text-muted);
    margin-bottom: var(--spacing-md);
  }

  .btn-switch {
    padding: var(--spacing-sm) var(--spacing-md);
    background: var(--color-bg-elevated);
    border: 1px solid var(--color-border);
    border-radius: var(--radius-md);
    color: var(--color-text-secondary);

    i {
      font-size: 14px;
      margin-right: var(--spacing-xs);
      margin-bottom: 0;
    }

    &:hover {
      background: var(--color-bg-card);
      color: var(--color-gold);
    }
  }
}

.interactive-list {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-md);
  max-height: 400px;
  overflow-y: auto;
}

.interactive-item {
  background: var(--color-bg-dark);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  padding: var(--spacing-md);
  transition: border-color var(--transition-fast);

  &:hover {
    border-color: var(--color-gold);
  }

  &.item-delete,
  &.item-remove,
  &.item-unset {
    border-left: 3px solid var(--color-danger);
  }

  &.item-set,
  &.item-replace {
    border-left: 3px solid var(--color-success);
  }

  &.item-add,
  &.item-insert {
    border-left: 3px solid var(--color-info);
  }

  // 验证错误状态
  &.item-error {
    border-color: var(--color-danger) !important;
    border-left: 3px solid var(--color-danger) !important;
    background: rgba(255, 107, 107, 0.05);

    &:hover {
      border-color: var(--color-danger) !important;
    }
  }

  // 当前定位的错误 - 更明显的高亮
  &.current-error {
    border-color: var(--color-danger) !important;
    border-left: 4px solid var(--color-danger) !important;
    background: rgba(255, 107, 107, 0.15) !important;
    box-shadow:
      0 0 0 3px rgba(255, 107, 107, 0.25),
      0 4px 12px rgba(255, 107, 107, 0.2);
    transform: scale(1.01);
    position: relative;

    &::after {
      content: '当前错误';
      position: absolute;
      top: -10px;
      right: 10px;
      background: var(--color-danger);
      color: white;
      font-size: 10px;
      padding: 2px 8px;
      border-radius: var(--radius-sm);
      font-weight: 600;
    }
  }

  // 闪烁效果
  &.error-flash {
    animation: error-flash-anim 0.5s ease-in-out 2;
  }
}

// 错误闪烁动画
@keyframes error-flash-anim {
  0%,
  100% {
    box-shadow: 0 0 0 3px rgba(255, 107, 107, 0.25);
  }
  50% {
    box-shadow:
      0 0 0 6px rgba(255, 107, 107, 0.5),
      0 0 20px rgba(255, 107, 107, 0.3);
  }
}

.item-error-icon {
  display: flex;
  align-items: center;
  gap: 4px;
  color: var(--color-danger);
  animation: pulse-error 2s infinite;

  .error-count {
    font-size: 11px;
    font-weight: 600;
    background: var(--color-danger);
    color: white;
    padding: 1px 5px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
  }
}

.item-validation-errors {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-xs);
  margin-bottom: var(--spacing-sm);
}

.item-validation-error {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: var(--spacing-sm);
  padding: var(--spacing-sm);
  background: rgba(255, 107, 107, 0.1);
  border-radius: var(--radius-sm);
  font-size: 12px;

  i {
    color: var(--color-danger);
    flex-shrink: 0;
  }

  .error-field {
    color: var(--color-danger);
    font-weight: 600;
    font-family: var(--font-mono);
    background: rgba(255, 107, 107, 0.2);
    padding: 2px 6px;
    border-radius: var(--radius-sm);
  }

  .error-msg {
    color: var(--color-danger);
  }

  .expected-hint {
    color: var(--color-text-muted);
    font-style: italic;
    font-size: 11px;
    margin-left: auto;
  }
}

.input-error {
  border-color: var(--color-danger) !important;
  background: rgba(255, 107, 107, 0.05) !important;

  &:focus {
    border-color: var(--color-danger) !important;
    box-shadow: 0 0 0 2px rgba(255, 107, 107, 0.2) !important;
  }
}

.item-header {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  margin-bottom: var(--spacing-sm);
}

.item-type {
  @extend .cmd-type;
}

.item-path {
  flex: 1;
  font-family: var(--font-mono);
  font-size: 13px;
  color: var(--color-text-primary);
  word-break: break-all;
}

.btn-delete {
  padding: var(--spacing-xs);
  background: transparent;
  border: none;
  color: var(--color-text-muted);
  border-radius: var(--radius-sm);
  opacity: 0;
  transition: all var(--transition-fast);

  .interactive-item:hover & {
    opacity: 1;
  }

  &:hover {
    color: var(--color-danger);
    background: rgba(255, 107, 107, 0.1);
  }
}

.item-value {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-xs);

  label {
    font-size: 11px;
    color: var(--color-text-muted);
    text-transform: uppercase;
  }

  input,
  textarea {
    padding: var(--spacing-sm);
    background: var(--color-bg-card);
    border: 1px solid var(--color-border);
    border-radius: var(--radius-sm);
    font-family: var(--font-mono);
    font-size: 13px;
    color: var(--color-text-primary);
    transition: border-color var(--transition-fast);

    &:focus {
      border-color: var(--color-gold);
      outline: none;
    }
  }

  textarea {
    resize: vertical;
    min-height: 120px;
    max-height: 300px;
    overflow-y: auto;
    scroll-behavior: smooth;

    // 优化滚动条样式
    &::-webkit-scrollbar {
      width: 8px;
    }

    &::-webkit-scrollbar-track {
      background: var(--color-bg-dark);
      border-radius: 4px;
    }

    &::-webkit-scrollbar-thumb {
      background: var(--color-text-muted);
      border-radius: 4px;

      &:hover {
        background: var(--color-text-secondary);
      }
    }
  }
}

.item-reason {
  margin-top: var(--spacing-sm);
  font-size: 12px;
  color: var(--color-text-muted);
  font-style: italic;

  i {
    margin-right: var(--spacing-xs);
  }
}

// ═══ Footer ═══
.dialog-footer {
  display: flex;
  justify-content: flex-end;
  gap: var(--spacing-sm);
  padding: var(--spacing-md) var(--spacing-lg);
  border-top: 1px solid var(--color-border);
}

.btn-secondary,
.btn-primary,
.btn-minimize {
  display: flex;
  align-items: center;
  gap: var(--spacing-xs);
  padding: var(--spacing-sm) var(--spacing-lg);
  border-radius: var(--radius-md);
  font-size: 14px;
  font-weight: 600;
  transition: all var(--transition-fast);
}

.btn-secondary {
  background: transparent;
  border: 1px solid var(--color-border);
  color: var(--color-text-secondary);

  &:hover {
    background: var(--color-bg-elevated);
    color: var(--color-danger);
    border-color: var(--color-danger);
  }
}

.btn-minimize {
  background: var(--color-bg-elevated);
  border: 1px solid var(--color-border);
  color: var(--color-text-secondary);

  &:hover {
    background: var(--color-bg-dark);
    color: var(--color-text-primary);
  }
}

.btn-primary {
  background: var(--color-gold);
  color: var(--color-bg-dark);

  &:hover:not(:disabled) {
    filter: brightness(1.1);
  }

  &:disabled {
    opacity: 0.5;
    cursor: not-allowed;
  }
}

.btn-next-error {
  display: flex;
  align-items: center;
  gap: var(--spacing-xs);
  padding: var(--spacing-sm) var(--spacing-lg);
  border-radius: var(--radius-md);
  font-size: 14px;
  font-weight: 600;
  background: var(--color-danger);
  border: none;
  color: white;
  transition: all var(--transition-fast);

  &:hover {
    filter: brightness(1.1);
  }

  .error-counter {
    font-size: 12px;
    opacity: 0.9;
  }
}

// ═══ Cancel Confirm Dialog ═══
.cancel-confirm-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.7);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: calc(var(--z-modal) + 1);
}

.cancel-confirm-dialog {
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  padding: var(--spacing-xl);
  max-width: 400px;
  text-align: center;

  .confirm-icon {
    width: 60px;
    height: 60px;
    margin: 0 auto var(--spacing-md);
    background: rgba(255, 193, 7, 0.1);
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;

    i {
      font-size: 28px;
      color: var(--color-warning, #ffc107);
    }
  }

  h3 {
    font-size: 18px;
    color: var(--color-text-primary);
    margin: 0 0 var(--spacing-sm);
  }

  p {
    font-size: 14px;
    color: var(--color-text-muted);
    margin: 0 0 var(--spacing-lg);
  }

  .confirm-actions {
    display: flex;
    gap: var(--spacing-sm);
    justify-content: center;
  }

  .btn-back,
  .btn-confirm-cancel {
    display: flex;
    align-items: center;
    gap: var(--spacing-xs);
    padding: var(--spacing-sm) var(--spacing-lg);
    border-radius: var(--radius-md);
    font-size: 14px;
    font-weight: 600;
    transition: all var(--transition-fast);
  }

  .btn-back {
    background: var(--color-bg-elevated);
    border: 1px solid var(--color-border);
    color: var(--color-text-secondary);

    &:hover {
      background: var(--color-bg-dark);
      color: var(--color-text-primary);
    }
  }

  .btn-confirm-cancel {
    background: var(--color-danger);
    color: white;

    &:hover {
      filter: brightness(1.1);
    }
  }
}

// ═══ Transitions ═══
.modal-enter-active,
.modal-leave-active {
  transition: all 0.3s ease;

  .mvu-confirm-dialog {
    transition: all 0.3s ease;
  }
}

.modal-enter-from,
.modal-leave-to {
  opacity: 0;

  .mvu-confirm-dialog {
    transform: translateY(100%);
  }
}

.fade-enter-active,
.fade-leave-active {
  transition: opacity 0.2s ease;
}

.fade-enter-from,
.fade-leave-to {
  opacity: 0;
}
