
.m-dashboard {
  padding: var(--mobile-padding);
  display: flex;
  flex-direction: column;
  gap: 8px;
}

// ═══ 场景横幅 ═══
.scene-banner {
  background: linear-gradient(135deg, rgba(196, 30, 58, 0.08) 0%, rgba(216, 166, 87, 0.05) 100%);
  border: 1px solid var(--color-border);
  border-radius: var(--mobile-radius);
  padding: var(--mobile-padding);
}

.scene-top {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 6px;
}

.scene-type-tag {
  padding: 2px 8px;
  font-size: 10px;
  background: var(--color-bg-elevated);
  border-radius: var(--radius-full);
  color: var(--color-text-secondary);
}

.mood-tag {
  font-size: 10px;
  color: var(--color-romance-light);
  i { font-size: 10px; }
}

.scene-desc {
  font-size: 13px;
  line-height: 1.6;
  color: var(--color-text-secondary);
  margin: 0 0 6px;
}

.scene-chars {
  display: flex;
  flex-wrap: wrap;
  gap: 4px;
  margin-bottom: 6px;
}

.scene-topic {
  padding: 6px 10px;
  background: rgba(216, 166, 87, 0.1);
  border-radius: var(--radius-sm);
  font-size: 11px;
  color: var(--color-gold);

  i { margin-right: 4px; }
}

// ═══ 快捷导航 ═══
.quick-nav {
  padding: 4px 0;
}

.nav-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 8px;
}

.nav-btn {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
  padding: 10px 6px;
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--mobile-radius);
  cursor: pointer;
  transition: all 0.2s ease;

  &:active { background: var(--color-bg-elevated); }
}

.nav-icon {
  width: 36px;
  height: 36px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: var(--color-bg-elevated);
  border-radius: var(--radius-md);
  font-size: 16px;
  color: var(--color-gold);

  &.purple { color: #9b59b6; background: rgba(155, 89, 182, 0.12); }
  &.romance { color: var(--color-romance-light); background: rgba(255, 77, 109, 0.12); }
  &.danger { color: var(--color-danger); background: rgba(255, 107, 107, 0.12); }
  &.success { color: var(--color-success); background: rgba(74, 193, 142, 0.12); }
}

.nav-val {
  font-size: 18px;
  font-weight: 700;
  color: var(--color-text-primary);
  font-family: var(--font-display);
  line-height: 1;
}

.nav-label {
  font-size: 10px;
  color: var(--color-text-muted);
}

// ═══ 新闻列表 ═══
.news-list {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.news-item {
  display: flex;
  align-items: flex-start;
  gap: 8px;
  font-size: 12px;
  line-height: 1.5;
  padding: 4px 0;

  i {
    flex-shrink: 0;
    width: 14px;
    font-size: 11px;
    margin-top: 2px;
  }

  &.event { color: var(--color-gold); }
  &.central { color: #9b59b6; }
  &.province { color: #3498db; }
  &.local { color: #1abc9c; }
  &.rumor { color: var(--color-warning); }
  &.reputation { color: var(--color-romance-light); }
}

// ═══ 待办列表 ═══
.todo-list {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.todo-body {
  flex: 1;
  min-width: 0;
}

.todo-main {
  display: flex;
  align-items: center;
  gap: 6px;
}

.todo-urgency {
  font-size: 10px;
  padding: 1px 6px;
  border-radius: var(--radius-sm);
  background: var(--color-bg-card);
  color: var(--color-text-muted);
  flex-shrink: 0;
}

.urgent .todo-urgency { background: rgba(255, 107, 107, 0.15); color: var(--color-danger); }
.high .todo-urgency { background: rgba(224, 195, 108, 0.15); color: var(--color-warning); }

.todo-text {
  font-size: 13px;
  color: var(--color-text-primary);
}

.todo-meta {
  font-size: 11px;
  color: var(--color-text-muted);
  margin-top: 2px;
  i { margin-right: 4px; }
}

.empty-hint {
  text-align: center;
  color: var(--color-text-muted);
  font-size: 13px;
  padding: 16px;
}

// ═══ 关系索引 ═══
.relation-tags {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.rel-item, .rel-group {
  display: flex;
  align-items: flex-start;
  gap: 8px;
  padding: 6px 10px;
  background: var(--color-bg-elevated);
  border-radius: var(--radius-sm);
  border-left: 3px solid var(--field-color, var(--color-border));
}

.rel-label {
  font-size: 10px;
  color: var(--color-text-muted);
  flex-shrink: 0;
  padding-top: 2px;
}

.rel-names {
  display: flex;
  flex-wrap: wrap;
  gap: 4px;
}
