
.m-romance {
  padding: var(--mobile-padding);
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.romance-card {
  background: var(--color-bg-card);
  border: 1px solid rgba(196, 30, 58, 0.2);
  border-radius: var(--mobile-radius);
  overflow: hidden;
  transition: border-color 0.2s ease;

  &.expanded {
    border-color: var(--color-romance);
  }
}

.card-main {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px;
  cursor: pointer;
}

.card-cover {
  width: 52px;
  height: 52px;
  border-radius: var(--radius-md);
  background: linear-gradient(135deg, rgba(196, 30, 58, 0.3), rgba(120, 20, 40, 0.2));
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  background-size: cover;
  background-position: center;

  .default-icon {
    font-size: 22px;
    color: rgba(255, 77, 109, 0.5);
  }
}

.card-info {
  flex: 1;
  min-width: 0;

  h3 {
    font-size: 15px;
    font-weight: 700;
    color: var(--color-text-primary);
    margin: 0;
  }

  .char-pos {
    font-size: 11px;
    color: var(--color-text-muted);
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }
}

.status-chips {
  display: flex;
  gap: 4px;
  margin-top: 4px;
}

.stage {
  font-size: 10px;
  padding: 1px 6px;
  border-radius: var(--radius-full);
  background: rgba(255, 77, 109, 0.12);
  color: var(--color-romance-light);
  &.hot { background: rgba(255, 77, 109, 0.2); color: var(--color-romance); }
  &.cold { background: rgba(122, 162, 247, 0.12); color: var(--color-info); }
}

.emotion {
  font-size: 10px;
  padding: 1px 6px;
  border-radius: var(--radius-full);
  background: var(--color-bg-elevated);
  color: var(--color-text-muted);
  &.positive { color: var(--color-success); background: rgba(74, 193, 142, 0.12); }
  &.negative { color: var(--color-danger); background: rgba(255, 107, 107, 0.12); }
  &.warning { color: var(--color-warning); background: rgba(224, 195, 108, 0.12); }
}

.card-meters {
  display: flex;
  flex-direction: column;
  gap: 4px;
  flex-shrink: 0;
}

.meter {
  display: flex;
  align-items: center;
  gap: 4px;
  font-size: 12px;
  font-weight: 600;

  &.favor { color: var(--color-romance-light); i { font-size: 10px; } }
  &.danger { color: var(--color-text-muted); i { font-size: 10px; } }
  &.danger.high { color: var(--color-warning); }
  &.danger.critical { color: var(--color-danger); }
}

// ═══ 展开详情 ═══
.card-detail {
  padding: 0 10px 10px;
  border-top: 1px solid var(--color-border);
  margin-top: 0;
}

.detail-row {
  display: flex;
  gap: 8px;
  padding: 6px 0;
  font-size: 12px;
  color: var(--color-text-secondary);
  border-bottom: 1px solid rgba(255, 255, 255, 0.03);

  &:last-child { border-bottom: none; }
}

.detail-label {
  font-size: 11px;
  color: var(--color-text-muted);
  flex-shrink: 0;
  width: 50px;
}

.detail-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 4px;
  padding: 6px 0;
}

.id-tag {
  padding: 2px 6px;
  font-size: 9px;
  background: rgba(255, 77, 109, 0.1);
  border-radius: var(--radius-sm);
  color: var(--color-romance-light);
}

.detail-event {
  padding: 8px 10px;
  background: var(--color-bg-elevated);
  border-radius: var(--radius-sm);
  font-size: 12px;
  color: var(--color-text-muted);
  font-style: italic;
  margin: 6px 0;

  i { margin-right: 6px; font-size: 10px; }
}

.upload-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  width: 100%;
  padding: 8px;
  margin-top: 8px;
  background: var(--color-bg-elevated);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  color: var(--color-text-muted);
  font-size: 12px;
  min-height: var(--touch-min-size);
}

// ═══ 图片上传弹窗 ═══
.image-uploader-modal {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.7);
  z-index: 100;
  display: flex;
  align-items: flex-end;
}

.uploader-dialog {
  width: 100%;
  background: var(--color-bg-card);
  border-radius: var(--mobile-radius) var(--mobile-radius) 0 0;
  max-height: 80vh;
  overflow-y: auto;
}

.uploader-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--mobile-padding);
  border-bottom: 1px solid var(--color-border);

  h3 {
    font-size: 15px;
    font-weight: 600;
    color: var(--color-text-primary);
    margin: 0;
    i { color: var(--color-gold); margin-right: 6px; }
  }

  .close-btn {
    width: 32px;
    height: 32px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: var(--color-bg-elevated);
    border-radius: var(--radius-md);
    color: var(--color-text-muted);
  }
}

.uploader-body {
  padding: var(--mobile-padding);
}

.empty-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 60px 0;
  gap: 12px;
  color: var(--color-text-muted);

  i { font-size: 48px; color: var(--color-romance); opacity: 0.3; }
}
