
// ═══ 根容器 ═══
.mobile-app {
  display: flex;
  flex-direction: column;
  width: 100%;
  min-height: 50vh;
  background: var(--color-bg-dark);
}

// ═══ 顶部紧凑栏 ═══
.mobile-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: var(--header-height);
  padding: 0 var(--mobile-padding);
  background: var(--color-bg-card);
  border-bottom: 1px solid var(--color-border);
  flex-shrink: 0;
  z-index: 10;

  &.startup-mode {
    background: linear-gradient(90deg, rgba(196, 30, 58, 0.08) 0%, var(--color-bg-card) 100%);
    border-bottom-color: rgba(196, 30, 58, 0.2);
  }
}

// ═══ 日期时间地点栏 ═══
.datetime-bar {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 4px 12px;
  padding: 6px var(--mobile-padding);
  background: var(--color-bg-card);
  border-bottom: 1px solid var(--color-border);
  font-size: 11px;
  color: var(--color-text-secondary);
  flex-shrink: 0;

  .dt-item {
    display: flex;
    align-items: center;
    gap: 4px;
    white-space: nowrap;

    i {
      font-size: 10px;
      color: var(--color-gold);
    }
  }

  .location i {
    color: #3498db;
  }
}

.header-left {
  .header-title {
    font-family: var(--font-display);
    font-size: 15px;
    font-weight: 700;
    background: var(--color-romance-gradient);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;

    &.startup {
      letter-spacing: 2px;
    }
  }
}

.header-right {
  display: flex;
  align-items: center;
  gap: 8px;
}

.player-chip {
  display: flex;
  align-items: center;
  gap: 4px;
  padding: 3px 10px;
  background: var(--color-bg-elevated);
  border-radius: var(--radius-full);
  font-size: 12px;
  font-weight: 600;
  color: var(--color-text-primary);

  small {
    font-size: 10px;
    font-weight: 400;
    color: var(--color-gold);
  }
}

.mvu-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 32px;
  height: 32px;
  background: transparent;
  border: 1px solid var(--color-gold);
  border-radius: var(--radius-md);
  color: var(--color-gold);
  font-size: 14px;

  &.parsing {
    border-color: var(--color-danger);
    background: rgba(255, 107, 107, 0.15);
    color: var(--color-danger);
    animation: pulse-mvu 1s ease-in-out infinite;
  }

  &.minimized {
    border-color: var(--color-info);
    background: rgba(122, 162, 247, 0.15);
    color: var(--color-info);
  }

  &.startup {
    border-color: var(--color-romance);
    background: rgba(196, 30, 58, 0.15);
    color: var(--color-romance);
  }
}

@keyframes pulse-mvu {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.5; }
}

.mobile-content {
  flex: 1;
}

// ═══ 底部标签栏 ═══
.tab-bar {
  display: flex;
  height: var(--tab-bar-height);
  background: var(--color-bg-card);
  border-top: 1px solid var(--color-border);
  flex-shrink: 0;
  z-index: 10;
  padding-bottom: env(safe-area-inset-bottom, 0);

  &.startup-mode {
    border-top-color: rgba(196, 30, 58, 0.2);
  }
}

.tab-item {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 2px;
  text-decoration: none;
  color: var(--color-text-muted);
  font-size: 10px;
  transition: all 0.2s ease;
  position: relative;
  background: none;
  border: none;
  cursor: pointer;
  min-height: var(--tab-bar-height);

  i {
    font-size: 18px;
    transition: color 0.2s ease;
  }

  span {
    font-weight: 500;
  }

  &.active {
    color: var(--color-romance);

    i {
      color: var(--color-romance);
    }
  }
}

.tab-badge {
  position: absolute;
  top: 4px;
  right: 50%;
  transform: translateX(14px);
  min-width: 16px;
  height: 16px;
  padding: 0 4px;
  font-size: 9px;
  font-weight: 600;
  background: var(--color-romance);
  color: white;
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
}

// ═══ 更多菜单（底部弹出） ═══
.more-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.5);
  z-index: 50;
}

.more-sheet {
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
  background: var(--color-bg-card);
  border-radius: var(--mobile-radius) var(--mobile-radius) 0 0;
  padding: var(--mobile-padding);
  padding-bottom: calc(var(--tab-bar-height) + var(--mobile-padding) + env(safe-area-inset-bottom, 0));
  z-index: 51;
  box-shadow: 0 -8px 32px rgba(0, 0, 0, 0.3);
}

.sheet-handle {
  width: 40px;
  height: 4px;
  background: var(--color-border);
  border-radius: 2px;
  margin: 0 auto 16px;
}

.sheet-grid {
  display: grid;
  grid-template-columns: repeat(5, 1fr);
  gap: 12px;
}

.sheet-item {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 6px;
  text-decoration: none;
  color: var(--color-text-secondary);
  font-size: 11px;
  position: relative;
  padding: 8px 0;

  &.active {
    color: var(--color-romance);
    .sheet-icon { border-color: var(--color-romance); }
  }
}

.sheet-icon {
  width: 44px;
  height: 44px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: var(--color-bg-elevated);
  border: 1px solid var(--color-border);
  border-radius: var(--mobile-radius);
  font-size: 18px;
  transition: all 0.2s ease;

  &.green { color: #27ae60; }
  &.orange { color: #e67e22; }
  &.teal { color: #1abc9c; }
  &.gray { color: #7f8c8d; }
  &.blue { color: #3498db; }
}

.sheet-badge {
  position: absolute;
  top: 2px;
  right: 50%;
  transform: translateX(20px);
  min-width: 16px;
  height: 16px;
  padding: 0 4px;
  font-size: 9px;
  font-weight: 600;
  background: var(--color-romance);
  color: white;
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
}

// ═══ 脏数据提示 ═══
.dirty-banner {
  position: fixed;
  top: var(--header-height);
  left: 0;
  right: 0;
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px var(--mobile-padding);
  background: rgba(255, 107, 107, 0.95);
  color: white;
  font-size: 13px;
  z-index: 20;

  .dirty-actions {
    margin-left: auto;
    display: flex;
    gap: 6px;

    button {
      width: 32px;
      height: 32px;
      border-radius: var(--radius-md);
      background: rgba(255, 255, 255, 0.2);
      color: white;
      display: flex;
      align-items: center;
      justify-content: center;

      &.save {
        background: rgba(255, 255, 255, 0.3);
      }
    }
  }
}

// ═══ 加载状态 ═══
.loading-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  height: 100%;
  gap: 16px;
  color: var(--color-text-muted);

  .loading-spinner {
    width: 32px;
    height: 32px;
    border: 3px solid var(--color-border);
    border-top-color: var(--color-romance);
    border-radius: 50%;
    animation: spin 0.8s linear infinite;
  }
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

// ═══ 弹窗按钮 ═══
.block-confirm-content {
  padding: var(--mobile-padding);
  font-size: 14px;
  color: var(--color-text-secondary);
}

.block-confirm-actions {
  display: flex;
  gap: 8px;

  button {
    flex: 1;
    padding: 10px;
    border-radius: var(--radius-md);
    font-size: 14px;
    font-weight: 600;
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 6px;
    min-height: var(--touch-min-size);
  }

  .btn-cancel {
    background: var(--color-bg-elevated);
    color: var(--color-text-secondary);
    border: 1px solid var(--color-border);
  }

  .btn-confirm {
    background: var(--color-gold);
    color: var(--color-bg-dark);
  }
}

// ═══ 过渡动画 ═══
.slide-sheet-enter-active, .slide-sheet-leave-active {
  transition: transform 0.3s cubic-bezier(0.25, 0.46, 0.45, 0.94);
}
.slide-sheet-enter-from, .slide-sheet-leave-to {
  transform: translateY(100%);
}

.slide-down-enter-active, .slide-down-leave-active {
  transition: transform 0.3s ease, opacity 0.3s ease;
}
.slide-down-enter-from, .slide-down-leave-to {
  transform: translateY(-100%);
  opacity: 0;
}

// ═══ isMobile 标记（用于桌面版共享组件调整行为） ═══
:root {
  --is-mobile: 1;
}
