
.m-assets {
  padding: var(--mobile-padding);
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.asset-summary {
  display: flex;
  gap: 6px;
}

.asset-num {
  flex: 1;
  text-align: center;
  padding: 10px 6px;
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--mobile-radius);

  .label { display: block; font-size: 10px; color: var(--color-text-muted); }
  .value { display: block; font-size: 16px; font-weight: 700; font-family: var(--font-display); color: var(--color-text-primary); }
  .value.gold { color: var(--color-gold); }
  .value.danger { color: var(--color-danger); }
}

.tab-row {
  display: flex;
  gap: 6px;
}

.tab-btn {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  padding: 10px;
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--mobile-radius);
  color: var(--color-text-muted);
  font-size: 13px;
  font-weight: 600;
  min-height: var(--touch-min-size);
  transition: all 0.2s ease;

  &.active {
    background: rgba(216, 166, 87, 0.1);
    border-color: var(--color-gold);
    color: var(--color-gold);
  }
}

.tab-count {
  font-size: 10px;
  padding: 0 5px;
  background: var(--color-romance);
  color: white;
  border-radius: 8px;
}

.item-top {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.item-name { font-size: 13px; font-weight: 600; color: var(--color-text-primary); }
.item-val { font-size: 12px; font-weight: 600; &.gold { color: var(--color-gold); } }

.item-desc {
  font-size: 12px;
  color: var(--color-text-secondary);
  margin: 4px 0;
  line-height: 1.4;
}

.item-meta {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  font-size: 11px;
  color: var(--color-text-muted);
  margin-top: 4px;

  i { font-size: 10px; margin-right: 3px; }
  .safe { color: var(--color-success); } .ok { color: var(--color-info); }
  .warn { color: var(--color-warning); } .danger { color: var(--color-danger); }
  .fatal { color: var(--color-danger); } .serious { color: var(--color-warning); }
}

.risk-tag, .usage-tag, .mine-type, .pressure-tag {
  font-size: 10px; padding: 1px 6px; border-radius: var(--radius-sm);
  background: var(--color-bg-card); color: var(--color-text-muted);
}
.risk-tag.critical { color: var(--color-danger); background: rgba(255, 107, 107, 0.12); }
.risk-tag.high { color: var(--color-warning); background: rgba(224, 195, 108, 0.12); }
.pressure-tag.urgent { color: var(--color-danger); background: rgba(255, 107, 107, 0.12); }
.pressure-tag.high { color: var(--color-warning); background: rgba(224, 195, 108, 0.12); }

.trigger-tip {
  margin-top: 4px;
  padding: 4px 8px;
  background: rgba(255, 107, 107, 0.08);
  border-radius: var(--radius-sm);
  font-size: 11px;
  color: var(--color-warning);
  i { margin-right: 4px; }
}

.empty-hint {
  text-align: center; color: var(--color-text-muted); font-size: 13px; padding: 16px;
}
