
.m-faction {
  padding: var(--mobile-padding);
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.my-faction-banner {
  background: linear-gradient(135deg, rgba(39, 174, 96, 0.1) 0%, rgba(216, 166, 87, 0.05) 100%);
  border: 1px solid rgba(39, 174, 96, 0.2);
  border-radius: var(--mobile-radius);
  padding: var(--mobile-padding);
}

.banner-top {
  display: flex;
  align-items: center;
  gap: 6px;
  margin-bottom: 4px;

  i { color: #27ae60; font-size: 14px; }

  .faction-label {
    font-size: 11px;
    color: var(--color-text-muted);
  }
}

.my-faction-banner h2 {
  font-size: 18px;
  font-weight: 700;
  color: var(--color-text-primary);
  margin: 0 0 6px;
}

.banner-meta {
  display: flex;
  gap: 12px;
  font-size: 11px;
  color: var(--color-text-muted);
}

.faction-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.faction-name {
  font-size: 14px;
  font-weight: 600;
  color: var(--color-text-primary);
}

.faction-rel {
  font-size: 10px;
  padding: 2px 8px;
  border-radius: var(--radius-full);
  background: var(--color-bg-card);

  &.ally { color: var(--color-success); background: rgba(74, 193, 142, 0.12); }
  &.enemy { color: var(--color-danger); background: rgba(255, 107, 107, 0.12); }
  &.neutral { color: var(--color-info); background: rgba(122, 162, 247, 0.12); }
}

.faction-meta {
  font-size: 11px;
  color: var(--color-text-muted);
  margin-top: 4px;

  i { font-size: 10px; margin-right: 4px; color: var(--color-text-muted); }
}

.empty-hint {
  text-align: center;
  color: var(--color-text-muted);
  font-size: 13px;
  padding: 40px;
}
