
.m-startup-info {
  padding: var(--mobile-padding);
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.intro-card {
  text-align: center;
  padding: 20px var(--mobile-padding);
  background: linear-gradient(135deg, rgba(196, 30, 58, 0.08), rgba(216, 166, 87, 0.05));
  border: 1px solid var(--color-border);
  border-radius: var(--mobile-radius);
}

.seal-icon {
  width: 56px; height: 56px; margin: 0 auto 8px;
  display: flex; align-items: center; justify-content: center;
  background: linear-gradient(135deg, var(--color-romance) 0%, #ff6b8a 100%);
  border-radius: 50%; box-shadow: 0 4px 16px rgba(196, 30, 58, 0.25);
  i { font-size: 24px; color: white; }
}

.intro-card h2 {
  font-family: var(--font-display); font-size: 22px; font-weight: 700;
  background: var(--color-romance-gradient); -webkit-background-clip: text;
  -webkit-text-fill-color: transparent; margin: 0 0 4px;
}

.intro-sub { font-size: 12px; color: var(--color-text-muted); margin: 0 0 8px; }
.intro-desc { font-size: 13px; color: var(--color-text-secondary); line-height: 1.6; margin: 0; }

.editor-card {
  background: var(--color-bg-card); border: 1px solid var(--color-border);
  border-radius: var(--mobile-radius); overflow: hidden;
}

.editor-header {
  display: flex; align-items: center; justify-content: space-between;
  padding: 10px var(--mobile-padding);
  background: var(--color-bg-elevated);
  border-bottom: 1px solid var(--color-border);
  font-size: 13px; font-weight: 600; color: var(--color-text-primary);
  i { color: var(--color-gold); margin-right: 6px; }
  .char-count { font-size: 11px; font-weight: 400; color: var(--color-text-muted); }
}

.editor-area {
  width: 100%; padding: var(--mobile-padding);
  background: transparent; border: none; color: var(--color-text-primary);
  font-size: 14px; line-height: 1.7; resize: vertical; min-height: 200px;
  &::placeholder { color: var(--color-text-muted); opacity: 0.7; }
  &:focus { outline: none; }
}

.action-btns { display: flex; gap: 8px; }

.action-btn {
  flex: 1; display: flex; align-items: center; gap: 10px;
  padding: 14px; border-radius: var(--mobile-radius); border: 2px solid transparent;
  min-height: 64px; transition: all 0.2s;

  i { font-size: 22px; }
  div { display: flex; flex-direction: column; text-align: left; }
  span { font-size: 14px; font-weight: 600; }
  small { font-size: 11px; opacity: 0.8; }

  &.gen {
    background: rgba(216, 166, 87, 0.1); border-color: rgba(216, 166, 87, 0.3); color: var(--color-gold);
    &:active { background: rgba(216, 166, 87, 0.2); }
  }

  &.confirm {
    background: rgba(196, 30, 58, 0.1); border-color: rgba(196, 30, 58, 0.3); color: var(--color-romance-light);
    &:active { background: rgba(196, 30, 58, 0.2); }
  }
}

.tip-card {
  display: flex; align-items: flex-start; gap: 10px;
  padding: 10px var(--mobile-padding);
  background: rgba(122, 162, 247, 0.06);
  border: 1px solid rgba(122, 162, 247, 0.15);
  border-radius: var(--mobile-radius);

  i { font-size: 16px; color: var(--color-info); margin-top: 2px; }
  p { margin: 0; font-size: 12px; color: var(--color-text-secondary); line-height: 1.5; }
}
