
.array-editor {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-sm);

  &.disabled {
    opacity: 0.6;
    pointer-events: none;
  }

  &.focused .editor-container {
    border-color: var(--color-gold);
  }
}

.editor-label {
  display: flex;
  justify-content: space-between;
  align-items: center;

  .label-text {
    font-size: 12px;
    color: var(--color-text-muted);
  }

  .item-count {
    font-size: 11px;
    color: var(--color-text-muted);
  }
}

.editor-container {
  padding: var(--spacing-sm);
  background: var(--color-bg-elevated);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  min-height: 40px;
  transition: border-color var(--transition-fast);
}

.tags-wrapper {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-xs);
  align-items: center;
}

.tag-item {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 3px 8px;
  background: var(--color-bg-card);
  border-radius: var(--radius-sm);
  font-size: 12px;
  color: var(--color-text-secondary);
  transition: all var(--transition-fast);

  // 颜色变体
  &.color-gold {
    background: rgba(216, 166, 87, 0.15);
    color: var(--color-gold);
  }

  &.color-romance {
    background: rgba(255, 77, 109, 0.15);
    color: var(--color-romance-light);
  }

  &.color-danger {
    background: rgba(255, 107, 107, 0.15);
    color: var(--color-danger);
  }

  &.color-success {
    background: rgba(74, 193, 142, 0.15);
    color: var(--color-success);
  }

  &.color-info {
    background: rgba(122, 162, 247, 0.15);
    color: var(--color-info);
  }

  &.color-warning {
    background: rgba(224, 195, 108, 0.15);
    color: var(--color-warning);
  }
}

.tag-text {
  max-width: 150px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.tag-remove {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 14px;
  height: 14px;
  padding: 0;
  background: transparent;
  border: none;
  border-radius: 50%;
  color: inherit;
  font-size: 10px;
  opacity: 0.6;
  cursor: pointer;
  transition: all var(--transition-fast);

  &:hover {
    opacity: 1;
    background: rgba(255, 107, 107, 0.2);
    color: var(--color-danger);
  }
}

.tag-input {
  flex: 1;
  min-width: 100px;
  padding: 4px;
  background: transparent;
  border: none;
  color: var(--color-text-primary);
  font-size: 12px;

  &::placeholder {
    color: var(--color-text-muted);
  }

  &:focus {
    outline: none;
  }
}

// ═══ 建议面板 ═══
.suggestions-panel {
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  overflow: hidden;
}

.suggestions-header {
  display: flex;
  align-items: center;
  gap: var(--spacing-xs);
  padding: var(--spacing-xs) var(--spacing-sm);
  background: var(--color-bg-elevated);
  border-bottom: 1px solid var(--color-border);
  font-size: 11px;
  color: var(--color-text-muted);

  i {
    color: var(--color-warning);
  }
}

.suggestions-list {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-xs);
  padding: var(--spacing-sm);
}

.suggestion-item {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 3px 8px;
  background: var(--color-bg-elevated);
  border: 1px dashed var(--color-border);
  border-radius: var(--radius-sm);
  font-size: 11px;
  color: var(--color-text-muted);
  cursor: pointer;
  transition: all var(--transition-fast);

  i {
    font-size: 9px;
  }

  &:hover {
    background: var(--color-bg-card);
    border-color: var(--color-gold);
    color: var(--color-gold);
  }
}

// ═══ 过渡动画 ═══
.tag-enter-active,
.tag-leave-active {
  transition: all 0.2s ease;
}

.tag-enter-from {
  opacity: 0;
  transform: scale(0.8);
}

.tag-leave-to {
  opacity: 0;
  transform: scale(0.8);
}

.tag-move {
  transition: transform 0.2s ease;
}
