
.character-form {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-md);
}

// ═══ 区块样式 ═══
.form-section {
  background: var(--color-bg-elevated);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  overflow: hidden;

  &.romance {
    .section-header h4 i {
      color: var(--color-romance-light);
    }
  }
}

.section-header {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  padding: var(--spacing-sm) var(--spacing-md);
  cursor: pointer;
  transition: background var(--transition-fast);

  &:hover {
    background: var(--color-bg-card);
  }

  .expand-icon {
    color: var(--color-text-muted);
    font-size: 12px;
    transition: transform var(--transition-fast);

    &.expanded {
      transform: rotate(90deg);
    }
  }

  h4 {
    flex: 1;
    display: flex;
    align-items: center;
    gap: var(--spacing-sm);
    font-size: 13px;
    font-weight: 600;
    color: var(--color-text-primary);
    margin: 0;

    i {
      color: var(--color-gold);
      font-size: 14px;
    }
  }
}

.section-body {
  padding: var(--spacing-md);
  border-top: 1px solid var(--color-border);
}

// ═══ 字段网格 ═══
.field-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: var(--spacing-md);

  @media (max-width: 500px) {
    grid-template-columns: 1fr;
  }
}

.field-row {
  display: flex;
  flex-direction: column;
  gap: 4px;

  &.full {
    grid-column: 1 / -1;
  }

  label {
    font-size: 11px;
    color: var(--color-text-muted);
    text-transform: uppercase;
    letter-spacing: 0.5px;

    .required {
      color: var(--color-danger);
    }
  }

  input[type='text'],
  input[type='number'],
  textarea {
    padding: var(--spacing-sm) var(--spacing-md);
    background: var(--color-bg-card);
    border: 1px solid var(--color-border);
    border-radius: var(--radius-md);
    color: var(--color-text-primary);
    font-size: 13px;

    &:focus {
      border-color: var(--color-gold);
      outline: none;
    }

    &:disabled {
      opacity: 0.6;
      cursor: not-allowed;
    }

    &::placeholder {
      color: var(--color-text-muted);
    }
  }

  textarea {
    resize: vertical;
    min-height: 60px;
  }
}

// ═══ 年龄输入 ═══
.age-input-wrapper {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);

  input {
    flex: 1;
  }

  .age-warning {
    font-size: 11px;
    padding: 2px 6px;
    border-radius: var(--radius-sm);
    white-space: nowrap;
    font-weight: 600;

    &.good {
      background: rgba(74, 193, 142, 0.15);
      color: var(--color-success);
    }

    &.caution {
      background: rgba(216, 166, 87, 0.15);
      color: var(--color-gold);
    }

    &.warning {
      background: rgba(255, 165, 0, 0.15);
      color: #ffa500;
    }

    &.danger {
      background: rgba(255, 107, 107, 0.15);
      color: var(--color-danger);
    }
  }
}

// ═══ 数值面板 ═══
.stats-panel {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-lg);
}
