
.m-characters {
  padding: var(--mobile-padding);
  display: flex;
  flex-direction: column;
  gap: 10px;
}

// ═══ 搜索栏 ═══
.search-bar {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.search-input {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 10px 12px;
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--mobile-radius);

  i { color: var(--color-text-muted); font-size: 14px; }

  input {
    flex: 1;
    background: transparent;
    color: var(--color-text-primary);
    font-size: 14px;
    border: none;
    outline: none;

    &::placeholder { color: var(--color-text-muted); }
  }
}

.filter-row {
  display: flex;
  gap: 6px;
}

.filter-sel {
  flex: 1;
  padding: 8px 10px;
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  color: var(--color-text-primary);
  font-size: 12px;
}

.add-btn {
  width: var(--touch-min-size);
  height: var(--touch-min-size);
  display: flex;
  align-items: center;
  justify-content: center;
  background: var(--color-gold);
  color: var(--color-bg-dark);
  border-radius: var(--radius-md);
  font-size: 16px;
}

// ═══ 2列网格 ═══
.char-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 8px;
}

.char-card {
  display: flex;
  flex-direction: column;
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--mobile-radius);
  overflow: clip;
  cursor: pointer;
  position: relative;
  transition: border-color 0.2s ease;

  &:active { background: var(--color-bg-elevated); }

  &.type-romance { border-color: rgba(255, 77, 109, 0.4); }
  &.type-backer { border-color: rgba(74, 193, 142, 0.4); }
  &.type-rival { border-color: rgba(255, 107, 107, 0.4); }
}

.card-avatar {
  width: 48px;
  height: 48px;
  border-radius: 50%;
  overflow: hidden;
  background: var(--color-bg-elevated);
  display: flex;
  align-items: center;
  justify-content: center;
  margin: 10px auto 4px;
  border: 2px solid var(--color-border);
  flex-shrink: 0;

  .default-avatar { font-size: 22px; color: var(--color-text-muted); }

  &.male {
    background: rgba(74, 144, 217, 0.12);
    border-color: rgba(74, 144, 217, 0.3);
    .default-avatar { color: #4a90d9; }
  }

  &.female {
    background: rgba(232, 67, 147, 0.12);
    border-color: rgba(232, 67, 147, 0.3);
    .default-avatar { color: #e84393; }
  }
}

.card-body {
  padding: 0 8px 8px;
  text-align: center;

  h4 {
    font-size: 14px;
    font-weight: 700;
    color: var(--color-text-primary);
    margin: 0 0 2px;
    &.male { color: #4a90d9; }
    &.female { color: #e84393; }
  }
}

.card-rank {
  font-size: 10px;
  color: var(--color-gold);
  font-weight: 600;
}

.card-unit {
  font-size: 9px;
  color: var(--color-text-muted);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.card-tags {
  display: flex;
  justify-content: center;
  gap: 3px;
  margin-top: 4px;
}

.tag {
  font-size: 8px;
  padding: 1px 5px;
  border-radius: var(--radius-sm);
  background: var(--color-bg-elevated);
  color: var(--color-text-muted);

  &.gold { background: rgba(216, 166, 87, 0.15); color: var(--color-gold); }
  &.romance { background: rgba(255, 77, 109, 0.15); color: var(--color-romance-light); }
  &.danger { background: rgba(255, 107, 107, 0.15); color: var(--color-danger); }
  &.success { background: rgba(74, 193, 142, 0.15); color: var(--color-success); }
}

.favor-bar {
  height: 3px;
  background: var(--color-bg-elevated);

  .favor-fill {
    height: 100%;
    &.high { background: linear-gradient(90deg, #4ac18e, #2ecc71); }
    &.mid { background: linear-gradient(90deg, #e0c36c, #f1c40f); }
    &.low { background: linear-gradient(90deg, #ff6b6b, #e74c3c); }
  }
}

.empty-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 12px;
  padding: 40px 0;
  color: var(--color-text-muted);
  i { font-size: 40px; }
}
