
.m-opportunities {
  padding: var(--mobile-padding);
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.tab-row { display: flex; gap: 4px; }

.tab-btn {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 4px;
  padding: 10px 6px;
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--mobile-radius);
  color: var(--color-text-muted);
  font-size: 12px;
  font-weight: 600;
  min-height: var(--touch-min-size);

  .badge {
    font-size: 10px; padding: 0 5px;
    background: var(--color-bg-elevated); border-radius: 8px; color: var(--color-text-muted);
  }

  &.active {
    &.danger { border-color: var(--color-danger); color: var(--color-danger); .badge { background: rgba(255, 107, 107, 0.2); color: var(--color-danger); } }
    &.success { border-color: var(--color-success); color: var(--color-success); .badge { background: rgba(74, 193, 142, 0.2); color: var(--color-success); } }
    &.info { border-color: var(--color-info); color: var(--color-info); .badge { background: rgba(122, 162, 247, 0.2); color: var(--color-info); } }
  }
}

.card-top {
  display: flex; align-items: center; gap: 6px;
}

.card-title { flex: 1; font-size: 13px; font-weight: 600; color: var(--color-text-primary); }
.card-desc { font-size: 12px; color: var(--color-text-secondary); margin: 4px 0; line-height: 1.4; }
.card-meta {
  display: flex; flex-wrap: wrap; gap: 8px; font-size: 11px; color: var(--color-text-muted);
  i { font-size: 10px; margin-right: 3px; }
  .high-prob { color: var(--color-danger); } .mid-prob { color: var(--color-warning); }
}

.card-tip {
  margin-top: 4px; padding: 4px 8px; border-radius: var(--radius-sm); font-size: 11px;
  i { margin-right: 4px; }
  &.info { background: rgba(122, 162, 247, 0.08); color: var(--color-info); }
  &.success { background: rgba(74, 193, 142, 0.08); color: var(--color-success); }
  &.warning { background: rgba(224, 195, 108, 0.08); color: var(--color-warning); }
}

.level-tag {
  font-size: 10px; padding: 1px 6px; border-radius: var(--radius-sm);
  background: var(--color-bg-card); color: var(--color-text-muted);
  &.fatal { color: var(--color-danger); background: rgba(255, 107, 107, 0.12); }
  &.severe, &.moderate { color: var(--color-warning); background: rgba(224, 195, 108, 0.12); }
  &.legendary { color: #ffd700; background: rgba(255, 215, 0, 0.12); }
  &.epic, &.good { color: var(--color-success); background: rgba(74, 193, 142, 0.12); }
}

.todo-body { flex: 1; min-width: 0; }
.todo-main { display: flex; align-items: center; gap: 6px; }
.todo-urgency {
  font-size: 10px; padding: 1px 6px; border-radius: var(--radius-sm);
  background: var(--color-bg-card); color: var(--color-text-muted); flex-shrink: 0;
}
.urgent .todo-urgency { color: var(--color-danger); background: rgba(255, 107, 107, 0.12); }
.high .todo-urgency { color: var(--color-warning); background: rgba(224, 195, 108, 0.12); }
.todo-text { font-size: 13px; color: var(--color-text-primary); }
.todo-sub {
  display: flex; flex-wrap: wrap; gap: 6px; margin-top: 4px; font-size: 11px; color: var(--color-text-muted);
  i { margin-right: 3px; }
}
.related { display: flex; align-items: center; gap: 4px; }

.completed { opacity: 0.5; .card-title, .card-desc, .todo-text { text-decoration: line-through; color: var(--color-text-muted); } }

.empty-hint {
  display: flex; flex-direction: column; align-items: center; gap: 8px;
  padding: 40px; color: var(--color-text-muted); font-size: 13px;
  i { font-size: 32px; opacity: 0.3; }
}
